package com.ibm.jp.automation.e2m;

import org.junit.jupiter.api.Test;
import picocli.CommandLine;

import java.io.PrintWriter;
import java.io.StringWriter;

import static org.junit.jupiter.api.Assertions.*;

/**
 * --help オプションが正しく動作すること、および --version オプションが
 * mixinStandardHelpOptions と競合しないことを確認するテスト。
 */
class HelpOptionTest {

    @Test
    void helpOptionExitsZeroAndPrintsUsage() {
        StringWriter sw = new StringWriter();
        CommandLine cmd = new CommandLine(new Main());
        cmd.setOut(new PrintWriter(sw));
        int exitCode = cmd.execute("--help");
        assertEquals(0, exitCode, "--help は終了コード 0 を返すべき");
        String output = sw.toString();
        assertTrue(output.contains("e2m"), "ヘルプにコマンド名が含まれるべき");
        assertTrue(output.contains("--groupId"), "ヘルプに --groupId が含まれるべき");
        assertTrue(output.contains("--version"), "ヘルプに --version が含まれるべき");
    }
}

