package com.ibm.jp.automation.e2m;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;
import org.w3c.dom.Document;
import org.w3c.dom.NodeList;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.nio.file.Path;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class PomGeneratorTest {

    @TempDir
    Path tempDir;

    private EclipseProject javaProject() {
        return new EclipseProject("MyApp", false, List.of("src"), "bin",
                List.of(), null, "17");
    }

    private EclipseProject webProject() {
        return new EclipseProject("MyWebApp", true, List.of("src"), "build/classes",
                List.of(), "WebContent", "11");
    }

    private Document parsePom() throws Exception {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        DocumentBuilder db = dbf.newDocumentBuilder();
        return db.parse(tempDir.resolve("pom.xml").toFile());
    }

    @Test
    void javaProject_noPackagingElement() throws Exception {
        PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "1.0", tempDir);
        Document doc = parsePom();
        NodeList packaging = doc.getElementsByTagName("packaging");
        assertEquals(0, packaging.getLength(), "<packaging> 要素はJavaプロジェクトでは省略される");
    }

    @Test
    void javaProject_coordinates() throws Exception {
        PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "2.0", tempDir);
        Document doc = parsePom();
        assertEquals("com.example", doc.getElementsByTagName("groupId").item(0).getTextContent());
        assertEquals("myapp", doc.getElementsByTagName("artifactId").item(0).getTextContent());
        assertEquals("2.0", doc.getElementsByTagName("version").item(0).getTextContent());
    }

    @Test
    void webProject_hasWarPackaging() throws Exception {
        PomGenerator.generate(webProject(), List.of(), "com.example", "webapp", "1.0", tempDir);
        Document doc = parsePom();
        NodeList packaging = doc.getElementsByTagName("packaging");
        assertEquals(1, packaging.getLength());
        assertEquals("war", packaging.item(0).getTextContent());
    }

    @Test
    void javaVersion_reflectedInProperties() throws Exception {
        PomGenerator.generate(javaProject(), List.of(), "com.example", "myapp", "1.0", tempDir);
        Document doc = parsePom();
        // maven.compiler.source プロパティ
        NodeList props = doc.getElementsByTagName("maven.compiler.source");
        assertEquals(1, props.getLength());
        assertEquals("17", props.item(0).getTextContent());
    }

    @Test
    void dependency_centralFound_noScope() throws Exception {
        MavenDependency dep = new MavenDependency("org.apache.commons", "commons-lang3", "3.12.0", null, null);
        PomGenerator.generate(javaProject(), List.of(dep), "com.example", "myapp", "1.0", tempDir);
        Document doc = parsePom();

        NodeList groupIds = doc.getElementsByTagName("groupId");
        // 最初はprojectのgroupId、2番目がdependencyのgroupId
        boolean found = false;
        for (int i = 0; i < groupIds.getLength(); i++) {
            if ("org.apache.commons".equals(groupIds.item(i).getTextContent())) {
                found = true;
            }
        }
        assertTrue(found, "依存のgroupIdが出力される");
        // scopeは出力されない
        NodeList scopes = doc.getElementsByTagName("scope");
        assertEquals(0, scopes.getLength(), "スコープなしの依存にscope要素は不要");
    }

    @Test
    void dependency_systemScope_hasScopeAndSystemPath() throws Exception {
        MavenDependency dep = new MavenDependency("mylib", "mylib", "0.0.0", "system", "/opt/libs/mylib.jar");
        PomGenerator.generate(javaProject(), List.of(dep), "com.example", "myapp", "1.0", tempDir);
        Document doc = parsePom();

        NodeList scopes = doc.getElementsByTagName("scope");
        assertEquals(1, scopes.getLength());
        assertEquals("system", scopes.item(0).getTextContent());

        NodeList systemPaths = doc.getElementsByTagName("systemPath");
        assertEquals(1, systemPaths.getLength());
        assertEquals("/opt/libs/mylib.jar", systemPaths.item(0).getTextContent());
    }

    @Test
    void compilerPlugin_presentWithCorrectVersion() throws Exception {
        PomGenerator.generate(webProject(), List.of(), "com.example", "webapp", "1.0", tempDir);
        Document doc = parsePom();
        NodeList source = doc.getElementsByTagName("source");
        assertEquals(1, source.getLength());
        assertEquals("11", source.item(0).getTextContent());
    }
}

package com.ibm.jp.automation.e2m;

import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

class ProjectCopierTest {

    @TempDir
    Path inputDir;

    @TempDir
    Path outputDir;

    /** テスト用のソースファイルを作成するヘルパー */
    private Path createFile(Path base, String relative, String content) throws Exception {
        Path file = base.resolve(relative);
        Files.createDirectories(file.getParent());
        Files.writeString(file, content);
        return file;
    }

    @Test
    void isTestFolder_detectsTestPaths() {
        assertTrue(ProjectCopier.isTestFolder("src/test/java"));
        assertTrue(ProjectCopier.isTestFolder("test"));
        assertTrue(ProjectCopier.isTestFolder("src-test"));
        assertTrue(ProjectCopier.isTestFolder("mytest"));
        assertFalse(ProjectCopier.isTestFolder("src"));
        assertFalse(ProjectCopier.isTestFolder("src/main/java"));
    }

    @Test
    void copy_javaSourceGoesToSrcMainJava() throws Exception {
        // src/com/example/Foo.java を作成
        createFile(inputDir, "src/com/example/Foo.java", "public class Foo {}");

        EclipseProject project = new EclipseProject("Foo", false, List.of("src"), "bin",
                List.of(), null, "17");

        ProjectCopier.copy(project, inputDir, outputDir);

        Path expected = outputDir.resolve("src/main/java/com/example/Foo.java");
        assertTrue(Files.exists(expected), "Javaファイルが src/main/java に配置される");
    }

    @Test
    void copy_resourceFileGoesToSrcMainResources() throws Exception {
        createFile(inputDir, "src/config.properties", "key=value");

        EclipseProject project = new EclipseProject("App", false, List.of("src"), "bin",
                List.of(), null, "11");

        ProjectCopier.copy(project, inputDir, outputDir);

        Path expected = outputDir.resolve("src/main/resources/config.properties");
        assertTrue(Files.exists(expected), "リソースファイルが src/main/resources に配置される");
    }

    @Test
    void copy_testSourceGoesToSrcTestJava() throws Exception {
        createFile(inputDir, "test/com/example/FooTest.java", "public class FooTest {}");

        EclipseProject project = new EclipseProject("Foo", false, List.of("test"), "bin",
                List.of(), null, "17");

        ProjectCopier.copy(project, inputDir, outputDir);

        Path expected = outputDir.resolve("src/test/java/com/example/FooTest.java");
        assertTrue(Files.exists(expected), "テストJavaファイルが src/test/java に配置される");
    }

    @Test
    void copy_webContentGoesToSrcMainWebapp() throws Exception {
        createFile(inputDir, "WebContent/index.html", "<html/>");
        createFile(inputDir, "WebContent/WEB-INF/web.xml", "<web-app/>");

        EclipseProject project = new EclipseProject("WebApp", true, List.of("src"), "build/classes",
                List.of(), "WebContent", "11");

        ProjectCopier.copy(project, inputDir, outputDir);

        assertTrue(Files.exists(outputDir.resolve("src/main/webapp/index.html")),
                "index.html が src/main/webapp に配置される");
        assertTrue(Files.exists(outputDir.resolve("src/main/webapp/WEB-INF/web.xml")),
                "web.xml が src/main/webapp/WEB-INF に配置される");
    }

    @Test
    void copy_missingSourceFolder_doesNotThrow() throws Exception {
        EclipseProject project = new EclipseProject("App", false, List.of("nonexistent"), "bin",
                List.of(), null, "17");
        // 存在しないフォルダは警告を出してスキップ（例外は投げない）
        assertDoesNotThrow(() -> ProjectCopier.copy(project, inputDir, outputDir));
    }

    @Test
    void copy_webContentRootWithLeadingSlash() throws Exception {
        createFile(inputDir, "WebContent/index.jsp", "<%@ page %>");

        EclipseProject project = new EclipseProject("WebApp", true, List.of("src"), "bin",
                List.of(), "/WebContent", "11");  // 先頭スラッシュあり

        ProjectCopier.copy(project, inputDir, outputDir);

        assertTrue(Files.exists(outputDir.resolve("src/main/webapp/index.jsp")),
                "先頭スラッシュが除去されてWebコンテンツがコピーされる");
    }
}

