31 | import java.util.List;
32 | 
33 | /**
34 |  * EclipseProject情報と依存関係リストからMavenのpom.xmlを生成するクラス。
35 |  */
36 | public class PomGenerator {
37 | 
38 |     private PomGenerator() {}
39 | 
40 |     /**
41 |      * pom.xmlを生成して出力ディレクトリに保存する。
42 |      *
43 |      * @param eclipseProject パース済みEclipseプロジェクト情報
44 |      * @param dependencies   解決済み依存関係リスト
45 |      * @param groupId        生成するpom.xmlのgroupId
46 |      * @param artifactId     生成するpom.xmlのartifactId
47 |      * @param version        生成するpom.xmlのversion
48 |      * @param outputDir      出力ディレクトリ
49 |      * @throws Exception XML生成またはファイル書き込みに失敗した場合
50 |      */
51 |     public static void generate(
52 |             EclipseProject eclipseProject,
53 |             List<MavenDependency> dependencies,
54 |             String groupId,
55 |             String artifactId,
56 |             String version,
57 |             Path outputDir) throws Exception {
58 | 
59 |         DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
60 |         DocumentBuilder db = dbf.newDocumentBuilder();
61 |         Document doc = db.newDocument();
62 | 
63 |         // <project>
64 |         Element project = doc.createElement("project");
65 |         project.setAttribute("xmlns", "http://maven.apache.org/POM/4.0.0");
66 |         project.setAttribute("xmlns:xsi", "http://www.w3.org/2001/XMLSchema-instance");
67 |         project.setAttribute("xsi:schemaLocation",
68 |                 "http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd");
69 |         doc.appendChild(project);
70 | 
71 |         addTextElement(doc, project, "modelVersion", "4.0.0");
72 |         addTextElement(doc, project, "groupId", groupId);
73 |         addTextElement(doc, project, "artifactId", artifactId);
74 |         addTextElement(doc, project, "version", version);
75 | 
76 |         if (eclipseProject.webProject()) {
77 |             addTextElement(doc, project, "packaging", "war");
78 |         }
79 | 
80 |         // <properties>
81 |         String javaVersion = eclipseProject.javaVersion();
82 |         Element properties = doc.createElement("properties");
83 |         addTextElement(doc, properties, "project.build.sourceEncoding", "UTF-8");
84 |         addTextElement(doc, properties, "maven.compiler.source", javaVersion);
85 |         addTextElement(doc, properties, "maven.compiler.target", javaVersion);
86 |         project.appendChild(properties);
87 | 
88 |         // <dependencies>
89 |         if (!dependencies.isEmpty()) {
90 |             Element deps = doc.createElement("dependencies");
91 |             for (MavenDependency dep : dependencies) {
92 |                 Element dependency = doc.createElement("dependency");
93 |                 addTextElement(doc, dependency, "groupId", dep.groupId());
94 |                 addTextElement(doc, dependency, "artifactId", dep.artifactId());
95 |                 addTextElement(doc, dependency, "version", dep.version());
96 |                 if (dep.scope() != null && !dep.scope().isEmpty()) {
97 |                     addTextElement(doc, dependency, "scope", dep.scope());
98 |                 }
99 |                 if (dep.systemPath() != null) {
100 |                     addTextElement(doc, dependency, "systemPath", dep.systemPath());
101 |                 }
102 |                 deps.appendChild(dependency);
103 |             }
104 |             project.appendChild(deps);
105 |         }
106 | 
107 |         // <build><plugins><plugin> maven-compiler-plugin
108 |         Element build = doc.createElement("build");
109 |         Element plugins = doc.createElement("plugins");
110 |         Element plugin = doc.createElement("plugin");
111 |         addTextElement(doc, plugin, "groupId", "org.apache.maven.plugins");
112 |         addTextElement(doc, plugin, "artifactId", "maven-compiler-plugin");
113 |         addTextElement(doc, plugin, "version", "3.13.0");
114 |         Element configuration = doc.createElement("configuration");
115 |         addTextElement(doc, configuration, "source", javaVersion);
116 |         addTextElement(doc, configuration, "target", javaVersion);
117 |         plugin.appendChild(configuration);
118 |         plugins.appendChild(plugin);
119 |         build.appendChild(plugins);
120 |         project.appendChild(build);
121 | 
122 |         // XMLをファイルに書き出す
123 |         Files.createDirectories(outputDir);
124 |         TransformerFactory tf = TransformerFactory.newInstance();
125 |         Transformer transformer = tf.newTransformer();
126 |         transformer.setOutputProperty(OutputKeys.INDENT, "yes");
127 |         transformer.setOutputProperty(OutputKeys.ENCODING, "UTF-8");
128 |         transformer.setOutputProperty("{http://xml.apache.org/xslt}indent-amount", "2");
129 | 
130 |         Path pomPath = outputDir.resolve("pom.xml");
131 |         transformer.transform(new DOMSource(doc), new StreamResult(pomPath.toFile()));
132 | 
133 |         System.out.println("Generated: " + pomPath);
134 |     }
135 | 
136 |     private static void addTextElement(Document doc, Element parent, String tagName, String text) {
137 |         Element el = doc.createElement(tagName);
138 |         el.appendChild(doc.createTextNode(text));
139 |         parent.appendChild(el);
140 |     }
141 | }
