17 | package com.ibm.jp.automation.e2m;
18 | 
19 | import org.w3c.dom.Document;
20 | import org.w3c.dom.Element;
21 | import org.w3c.dom.NodeList;
22 | 
23 | import javax.xml.parsers.DocumentBuilder;
24 | import javax.xml.parsers.DocumentBuilderFactory;
25 | import java.nio.file.Files;
26 | import java.nio.file.Path;
27 | import java.util.ArrayList;
28 | import java.util.List;
29 | 
30 | /**
31 |  * Eclipseプロジェクトのメタデータファイルを解析して {@link EclipseProject} を返すパーサー。
32 |  */
33 | public class EclipseProjectParser {
34 | 
35 |     private static final String WTP_NATURE = "org.eclipse.wst.common.project.facet.core.nature";
36 |     private static final String DEFAULT_JAVA_VERSION = "11";
37 | 
38 |     /**
39 |      * 指定した入力ディレクトリを解析して {@link EclipseProject} を返す。
40 |      *
41 |      * @param inputDir Eclipseプロジェクトのルートディレクトリ
42 |      * @return 解析結果
43 |      * @throws Exception 解析中に発生した例外
44 |      */
45 |     public static EclipseProject parse(Path inputDir) throws Exception {
46 |         DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
47 |         DocumentBuilder builder = factory.newDocumentBuilder();
48 | 
49 |         // ── .project ──────────────────────────────────────────────
50 |         Path projectFile = inputDir.resolve(".project");
51 |         Document projectDoc = builder.parse(projectFile.toFile());
52 |         projectDoc.getDocumentElement().normalize();
53 | 
54 |         String projectName = projectDoc.getElementsByTagName("name")
55 |                 .item(0).getTextContent().trim();
56 | 
57 |         boolean webProject = false;
58 |         NodeList natures = projectDoc.getElementsByTagName("nature");
59 |         for (int i = 0; i < natures.getLength(); i++) {
60 |             if (WTP_NATURE.equals(natures.item(i).getTextContent().trim())) {
61 |                 webProject = true;
62 |                 break;
63 |             }
64 |         }
65 | 
66 |         // ── .classpath ────────────────────────────────────────────
67 |         Path classpathFile = inputDir.resolve(".classpath");
68 |         Document cpDoc = builder.parse(classpathFile.toFile());
69 |         cpDoc.getDocumentElement().normalize();
70 | 
71 |         List<String> sourceFolders = new ArrayList<>();
72 |         List<String> jarPaths = new ArrayList<>();
73 |         String outputFolder = null;
74 |         String javaVersion = DEFAULT_JAVA_VERSION;
75 | 
76 |         NodeList entries = cpDoc.getElementsByTagName("classpathentry");
77 |         for (int i = 0; i < entries.getLength(); i++) {
78 |             Element entry = (Element) entries.item(i);
79 |             String kind = entry.getAttribute("kind");
80 |             String path = entry.getAttribute("path");
81 | 
82 |             switch (kind) {
83 |                 case "src" -> sourceFolders.add(path);
84 |                 case "output" -> outputFolder = path;
85 |                 case "lib" -> jarPaths.add(path);
86 |                 case "con" -> {
87 |                     String version = extractJavaVersion(path);
88 |                     if (version != null) {
89 |                         javaVersion = version;
90 |                     }
91 |                 }
92 |             }
93 |         }
94 | 
95 |         // ── WTP: .settings/org.eclipse.wst.common.component ──────
96 |         String webContentRoot = null;
97 |         if (webProject) {
98 |             webContentRoot = parseWebContentRoot(inputDir, builder);
99 |         }
100 | 
101 |         return new EclipseProject(
102 |                 projectName,
103 |                 webProject,
104 |                 List.copyOf(sourceFolders),
105 |                 outputFolder,
106 |                 List.copyOf(jarPaths),
107 |                 webContentRoot,
108 |                 javaVersion
109 |         );
110 |     }
111 | 
112 |     /**
113 |      * `con` エントリの path から Java バージョン番号を抽出する。
114 |      * 例: "...JavaSE-17" → "17", "...java-11-openjdk" → "11"
115 |      */
116 |     private static String extractJavaVersion(String conPath) {
117 |         // JavaSE-XX / java-XX 形式を探す
118 |         int idx = conPath.lastIndexOf('/');
119 |         String segment = (idx >= 0) ? conPath.substring(idx + 1) : conPath;
120 | 
121 |         // JavaSE-XX
122 |         if (segment.contains("JavaSE-")) {
123 |             String after = segment.substring(segment.indexOf("JavaSE-") + "JavaSE-".length());
124 |             String version = after.split("[^0-9.]")[0];
125 |             if (!version.isEmpty()) {
126 |                 return version;
127 |             }
128 |         }
129 | 
130 |         // java-XX (例: java-17-openjdk)
131 |         if (segment.startsWith("java-")) {
132 |             String after = segment.substring("java-".length());
133 |             String version = after.split("[^0-9.]")[0];
134 |             if (!version.isEmpty()) {
135 |                 return version;
136 |             }
137 |         }
138 | 
139 |         return null;
140 |     }
141 | 
142 |     /**
143 |      * `.settings/org.eclipse.wst.common.component` を解析して Webコンテンツルートを返す。
144 |      * ファイルが存在しない場合は null を返す。
145 |      * 先頭の "/" は除去した相対パスとして返す。
146 |      */
147 |     private static String parseWebContentRoot(Path inputDir, DocumentBuilder builder) {
148 |         Path componentFile = inputDir.resolve(".settings")
149 |                 .resolve("org.eclipse.wst.common.component");
150 | 
151 |         if (!Files.exists(componentFile)) {
152 |             return null;
153 |         }
154 | 
155 |         try {
156 |             Document doc = builder.parse(componentFile.toFile());
157 |             doc.getDocumentElement().normalize();
158 | 
159 |             NodeList resources = doc.getElementsByTagName("wb-resource");
160 |             for (int i = 0; i < resources.getLength(); i++) {
161 |                 Element res = (Element) resources.item(i);
162 |                 if ("defaultRootSource".equals(res.getAttribute("tag"))) {
163 |                     String sourcePath = res.getAttribute("source-path");
164 |                     // 先頭の "/" を除去して相対パスに正規化
165 |                     if (sourcePath.startsWith("/")) {
166 |                         sourcePath = sourcePath.substring(1);
167 |                     }
168 |                     return sourcePath;
169 |                 }
170 |             }
171 |         } catch (Exception e) {
172 |             // ファイルが壊れている場合は null を返す
173 |         }
174 | 
175 |         return null;
176 |     }
177 | }
